export interface HowToStep {
  name: string;
  text: string;
  image?: string;
}

export interface BlogArticle {
  slug: string;
  title: string;
  seoTitle?: string;
  description: string;
  content: string;
  image: string;
  imageAlt?: string;
  author: string;
  datePublished: string;
  dateModified: string;
  publishDate?: string; // ISO date for scheduled publishing (defaults to datePublished if not set)
  photoSlot?: string; // Optional data-photo-slot attribute on the hero, marking it for a future real-photo swap
  category: string;
  readTime: string;
  faqs?: { question: string; answer: string }[];
  keywords: string[];
  relatedSlugs?: string[]; // Manual cluster override; falls back to recency in getRelatedArticles
  howToSteps?: HowToStep[]; // For instructional articles - enables HowTo schema
  howToTotalTime?: string; // ISO 8601 duration like "PT60M"
  howToSupplies?: string[]; // List of supplies / materials
  howToTools?: string[]; // List of tools needed
  youtubeVideoId?: string; // Optional Mercury Marine YouTube video reference
  youtubeVideoTitle?: string; // Title used for facade button + VideoObject schema
  videoAssetUrl?: string; // Optional self-hosted CDN video (Lovable Assets)
  videoAssetTitle?: string;
  videoAssetCaption?: string;
}

// Parses "YYYY-MM-DD" as local midnight (America/Toronto for our content),
// not UTC. Prevents posts from publishing a day early in EDT.
export function parseLocalDate(dateString: string): Date {
  const [y, m, d] = dateString.split('-').map(Number);
  return new Date(y, (m || 1) - 1, d || 1);
}

// Seasonal posts - only surface on the blog index during their relevant
// months (Ontario boating calendar). Months are 1-12. Posts not listed
// here are treated as year-round. Sitemap eligibility is NOT affected -
// these pages remain crawlable and indexable year-round (direct URLs
// still work), we just hide them from the blog index out of season so
// the feed feels timely instead of showing winterization in July.
const SEASONAL_POSTS: Record<string, number[]> = {
  // Winter / off-season buying & planning (Nov–Feb)
  'winter-repower-planning-guide':        [11, 12, 1, 2],
  'year-end-boat-motor-buying-guide':     [11, 12, 1, 2],
  '2026-mercury-model-preview':           [10, 11, 12, 1, 2],
  // Winterization (Sep–Dec)
  'boat-winterization-cost-ontario-2026':                [9, 10, 11, 12],
  'diy-mercury-outboard-winterization-guide':            [9, 10, 11, 12],
  'mercury-outboard-winterization-service-cost-ontario': [9, 10, 11, 12],
  // Winter storage (Sep–Mar)
  'winter-boat-storage-shrinkwrap-vs-indoor-ontario': [9, 10, 11, 12, 1, 2, 3],
  'outdoor-boat-storage-shrinkwrap-rice-lake':        [9, 10, 11, 12, 1, 2, 3],
  'winter-storage-near-toronto-hbw':                  [9, 10, 11, 12, 1, 2, 3],
  'boat-storage-kawartha-lakes':                      [9, 10, 11, 12, 1, 2, 3],
  // Spring commissioning & opener (Mar–May)
  'spring-outboard-commissioning-checklist': [3, 4, 5],
  'walleye-opener-boat-prep':                [3, 4, 5],
  // Late-season / cold-water safety (Sep–Nov)
  'late-season-boating-safety':              [9, 10, 11],
  // Active boating-season content (Apr–Oct)
  'ontario-boating-season-tips':              [4, 5, 6, 7, 8, 9, 10],
  'trent-severn-waterway-boating-guide-2026': [4, 5, 6, 7, 8, 9, 10],
  'rice-lake-boat-rentals-from-toronto-gta':  [4, 5, 6, 7, 8, 9],
};

export function isArticleInSeason(slug: string, now: Date = new Date()): boolean {
  const months = SEASONAL_POSTS[slug];
  if (!months) return true;
  return months.includes(now.getMonth() + 1);
}

// Helper to check if an article is published
export function isArticlePublished(article: BlogArticle): boolean {
  const publishDate = article.publishDate || article.datePublished;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const articleDate = parseLocalDate(publishDate);
  articleDate.setHours(0, 0, 0, 0);
  return articleDate <= today;
}

// Get all published articles (filters out future-dated AND out-of-season articles)
export function getPublishedArticles(): BlogArticle[] {
  const now = new Date();
  return blogArticles
    .filter(isArticlePublished)
    .filter(a => isArticleInSeason(a.slug, now))
    .sort((a, b) => {
      const da = new Date(a.publishDate || a.datePublished || 0).getTime();
      const db = new Date(b.publishDate || b.datePublished || 0).getTime();
      return db - da;
    });
}

// Get scheduled (unpublished) articles count
export function getScheduledArticlesCount(): number {
  return blogArticles.filter(article => !isArticlePublished(article)).length;
}

// Fallback/recycled hero images that historically marked draft/stub articles.
// Any article still using one of these is excluded from the sitemap.
const STUB_FALLBACK_HEROES = new Set<string>([
  '/lovable-uploads/How_to_Choose_The_Right_Horsepower_For_Your_Boat.png',
  '/lovable-uploads/Mercury_Maintenance_Schedule.png',
  '/lovable-uploads/Comparing_Motor_Families.png',
  '/lovable-uploads/mercury-service.jpg',
  '/lovable-uploads/Boat_Repowering_101_Hero.png',
  '/lovable-uploads/mercury-comparison.jpg',
]);

// Sitemap eligibility: include scheduled (future-dated) posts so search engines
// discover them ahead of release, but exclude drafts/stubs.
export function isArticleSitemapEligible(article: BlogArticle): boolean {
  const publishDate = article.publishDate || article.datePublished;
  if (!publishDate) return false;
  if (article.image && STUB_FALLBACK_HEROES.has(article.image)) return false;
  return true;
}

export function getSitemapEligibleArticles(): BlogArticle[] {
  return blogArticles.filter(isArticleSitemapEligible);
}

