export function getArticleBySlug(slug: string): BlogArticle | undefined {
  // Return the article whether or not its publishDate is in the future.
  // The /blog index uses getPublishedArticles() to hide unpublished entries
  // from listings, but direct URLs (internal links, sitemap, shared links)
  // must always render so we never silently redirect to /blog.
  return blogArticles.find(article => article.slug === slug);
}

export function getRelatedArticles(currentSlug: string, limit: number = 3): BlogArticle[] {
  const current = blogArticles.find(a => a.slug === currentSlug);
  if (current?.relatedSlugs?.length) {
    const manual = current.relatedSlugs
      .map(slug => blogArticles.find(a => a.slug === slug))
      .filter((a): a is BlogArticle => Boolean(a) && a!.slug !== currentSlug);
    if (manual.length > 0) return manual.slice(0, limit);
  }
  return blogArticles
    .filter(article => article.slug !== currentSlug && isArticlePublished(article))
    .sort((a, b) => {
      const da = new Date(a.publishDate || a.datePublished || 0).getTime();
      const db = new Date(b.publishDate || b.datePublished || 0).getTime();
      return db - da;
    })
    .slice(0, limit);
}
